    stream_ids: [serval.config.H2_MAX_CONCURRENT_STREAMS]u32 = [_]u32{0} ** serval.config.H2_MAX_CONCURRENT_STREAMS,

    pub fn selectUpstream(
        self: *@This(),
        ctx: *serval.Context,
