        self: *@This(),
        stream_id: u32,
        request: *const serval.Request,
        end_stream: bool,
        writer: *serval.server.H2ResponseWriter,
    ) !void {
        _ = writer;
        try testing.expectEqualStrings(self.path, request.path);
        try serval_grpc.validateRequest(request);
