            ")\n" ++
            "\n" ++
            "func main() {\n" ++
            "\tif len(os.Args) != 5 {\n" ++
            "\t\tfmt.Fprintln(os.Stderr, \"usage: main <target> <request-md> <expected-header> <expected-trailer>\")\n" ++
