    @memcpy(out[0..serval_h2.client_connection_preface.len], serval_h2.client_connection_preface);
    pos += serval_h2.client_connection_preface.len;

    const settings_frame = try appendH2Frame(out[pos..], .settings, 0, 0, &[_]u8{});
