    var out_buf: [3]u8 = undefined; // Only 3 bytes
    const chunked_data = "5\r\nhello\r\n0\r\n\r\n";
    const decoded = TestClient.decodeChunkedBody(chunked_data, &out_buf);
    try std.testing.expect(decoded == null);
}

