     1→// serval-lb/handler.zig
     2→//! Load Balancer Handler
     3→//!
     4→//! Health-aware round-robin upstream selection with automatic background probing.
     5→//! Backends recover automatically when probes succeed.
     6→//!
     7→//! TigerStyle: No allocation after init, bounded loops, explicit types.
     8→
     9→const std = @import("std");
    10→const assert = std.debug.assert;
    11→const core = @import("serval-core");
    12→const net = @import("serval-net");
    13→const health_mod = @import("serval-health");
    14→const prober = @import("serval-prober");
    15→const ssl = @import("serval-tls").ssl;
    16→
    17→const Context = core.Context;
    18→const Request = core.Request;
    19→const Upstream = core.Upstream;
    20→const LogEntry = core.LogEntry;
    21→const config = core.config;
    22→const DnsResolver = net.DnsResolver;
    23→
    24→const HealthState = health_mod.HealthState;
    25→const UpstreamIndex = config.UpstreamIndex;
    26→const MAX_UPSTREAMS = health_mod.MAX_UPSTREAMS;
    27→
    28→/// Load balancer configuration.
    29→pub const LbConfig = struct {
    30→    /// Consecutive failures before marking unhealthy.
    31→    unhealthy_threshold: u8 = config.DEFAULT_UNHEALTHY_THRESHOLD,
    32→    /// Consecutive successes before marking healthy.
    33→    healthy_threshold: u8 = config.DEFAULT_HEALTHY_THRESHOLD,
    34→    /// Enable background health probing (set false for tests).
    35→    enable_probing: bool = true,
    36→    /// Interval between probe cycles in milliseconds.
    37→    probe_interval_ms: u32 = config.DEFAULT_PROBE_INTERVAL_MS,
    38→    /// Timeout for each probe in milliseconds.
    39→    probe_timeout_ms: u32 = config.DEFAULT_PROBE_TIMEOUT_MS,
    40→    /// Health check path.
    41→    health_path: []const u8 = config.DEFAULT_HEALTH_PATH,
    42→};
    43→
    44→/// Load balancer handler with health tracking and automatic probing.
    45→///
    46→/// Features:
    47→/// - Health-aware round-robin selection (skips unhealthy backends)
    48→/// - Passive health updates via onLog (5xx = failure)
    49→/// - Active background probing for recovery
    50→/// - Graceful degradation when all backends unhealthy
    51→///
    52→/// TigerStyle: Embedded HealthState (no pointers), bounded by MAX_UPSTREAMS.
    53→pub const LbHandler = struct {
    54→    upstreams: []const Upstream,
    55→    health: HealthState,
    56→    next_idx: std.atomic.Value(u32),
    57→    probe_running: std.atomic.Value(bool),
    58→    probe_thread: ?std.Thread,
    59→    lb_config: LbConfig,
    60→
    61→    const Self = @This();
    62→
    63→    /// Initialize load balancer and start background prober.
    64→    /// TigerStyle C3: Out-pointer for large struct, stable pointer for thread.
    65→    /// TigerStyle: Caller provides SSL_CTX for TLS probes (caller owns lifetime).
    66→    ///
    67→    /// client_ctx: SSL_CTX for TLS health probes (required if any upstream has tls=true).
    68→    ///             Caller is responsible for creating and freeing the context.
    69→    ///             Pass null if all upstreams are plain HTTP.
    70→    /// dns_resolver: DNS resolver for hostname resolution in health probes.
    71→    ///               Required if probing is enabled. Caller owns lifetime.
    72→    pub fn init(
    73→        self: *Self,
    74→        upstreams: []const Upstream,
    75→        lb_config: LbConfig,
    76→        client_ctx: ?*ssl.SSL_CTX,
    77→        dns_resolver: ?*DnsResolver,
    78→    ) !void {
    79→        assert(upstreams.len > 0);
    80→        assert(upstreams.len <= MAX_UPSTREAMS);
    81→        assert(lb_config.probe_interval_ms > 0);
    82→        assert(lb_config.probe_timeout_ms > 0);
    83→        // S1: if probing enabled, dns_resolver must be provided
    84→        assert(!lb_config.enable_probing or dns_resolver != null);
