    81→///           onResponse, onResponseBody, onError, onLog,
    82→///           onConnectionOpen, onConnectionClose
    83→///
    84→/// TigerStyle: Compile-time safety, catch signature errors at build time not runtime.
    85→pub fn verifyHandler(comptime Handler: type) void {
    86→    // Required: selectUpstream
    87→    if (!@hasDecl(Handler, "selectUpstream")) {
    88→        @compileError("Handler must implement: pub fn selectUpstream(self: *Handler, ctx: *Context, request: *const Request) Upstream");
    89→    }
    90→
    91→    // Verify selectUpstream signature fully
    92→    verifySelectUpstream(Handler);
    93→
    94→    // Verify optional request hooks if declared
    95→    // onRequest signature: (self, ctx, request, response_buf) -> Action
    96→    verifyOptionalHook(Handler, "onRequest", &[_]type{ *Handler, *Context, *Request, []u8 }, Action);
    97→
    98→    // onRequestBody signature: (self, ctx, chunk, is_last) -> BodyAction
    99→    // Called for each request body chunk (WAF body inspection)
   100→    verifyOptionalHook(Handler, "onRequestBody", &[_]type{ *Handler, *Context, []const u8, bool }, BodyAction);
   101→
   102→    // onUpstreamRequest signature: (self, ctx, request) -> void
   103→    // Called after selectUpstream, before forwarding (path rewriting)
   104→    verifyOptionalHook(Handler, "onUpstreamRequest", &[_]type{ *Handler, *Context, *Request }, void);
   105→
