fn forwardFreshWebSocket(
    self: *Self,
    io: Io,
    client_stream: Io.net.Stream,
    client_tls: ?*TLSStream,
    request: *const Request,
    upstream: *const Upstream,
    initial_client_bytes: []const u8,
